  modalConfirm.addEventListener('click', submitCreateRoom);
  roomNameInput.addEventListener('keydown', e => { if (e.key === 'Enter') submitCreateRoom(); });

  // ── Leave Room ────────────────────────────────────────
  leaveBtn.addEventListener('click', () => {
    send({ type: 'leave_room' });
  });

  // ── Send Message ──────────────────────────────────────
  function submitMessage() {
